hooks.command:
node --input-type=module <<'EOF'
import { readFileSync } from 'fs';
const f = process.env.CLAUDE_TOOL_INPUT_FILE_PATH || '';
if (f.endsWith('.js')) {
  try {
    // Basic syntax check via dynamic import dry-run is not possible,
    // so we check for common mistakes in source text
    const src = readFileSync(f, 'utf8');
    if (src.includes('console.log(') && !f.includes('logger')) {
      console.warn('[hook] Prefer logger over console.log in', f);
    }
  } catch {}
}
EOF
